    /* -----------------------------------------------------------------------
     * AJAX handler
     * --------------------------------------------------------------------- */
    public function handle_form_submit() {
        // Verify nonce
        if ( ! check_ajax_referer( 'ajax_db_form_nonce', 'nonce', false ) ) {
            wp_send_json_error( [ 'message' => 'Security check failed. Please refresh the page.' ] );
        }

        // Sanitize inputs
        $name    = sanitize_text_field( wp_unslash( $_POST['adfs_name']    ?? '' ) );
        $email   = sanitize_email( wp_unslash( $_POST['adfs_email']   ?? '' ) );
        $phone   = sanitize_text_field( wp_unslash( $_POST['adfs_phone']   ?? '' ) );
        $subject = sanitize_text_field( wp_unslash( $_POST['adfs_subject'] ?? '' ) );
        $message = sanitize_textarea_field( wp_unslash( $_POST['adfs_message'] ?? '' ) );

        // Server-side validation
        $errors = [];

        if ( empty( $name ) ) {
            $errors['adfs_name'] = 'Full name is required.';
        }

        if ( empty( $email ) ) {
            $errors['adfs_email'] = 'Email address is required.';
        } elseif ( ! is_email( $email ) ) {
            $errors['adfs_email'] = 'Please enter a valid email address.';
        }

        if ( empty( $phone ) ) {
            $errors['adfs_phone'] = 'Phone number is required.';
        } elseif ( ! preg_match( '/^[+\d\s\-().]{7,20}$/', $phone ) ) {
            $errors['adfs_phone'] = 'Please enter a valid phone number.';
        }

        if ( empty( $subject ) ) {
            $errors['adfs_subject'] = 'Subject is required.';
        }

        if ( empty( $message ) ) {
            $errors['adfs_message'] = 'Message is required.';
        }

        if ( ! empty( $errors ) ) {
            wp_send_json_error( [ 'message' => 'Please fix the errors below.', 'fields' => $errors ] );
        }

        // Insert post
        $post_id = wp_insert_post( [
            'post_type'   => 'ajax_form_entry',
            'post_title'  => sanitize_text_field( $name . ' — ' . $subject ),
            'post_status' => 'private',
            'meta_input'  => [
                '_adfs_name'    => $name,
                '_adfs_email'   => $email,
                '_adfs_phone'   => $phone,
                '_adfs_subject' => $subject,
                '_adfs_message' => $message,
            ],
        ] );

        if ( is_wp_error( $post_id ) ) {
            wp_send_json_error( [ 'message' => 'Failed to save your submission. Please try again.' ] );
        }

        // Assign taxonomy term (subject as category)
        $term = term_exists( $subject, 'form_entry_subject' );
        if ( ! $term ) {
            $term = wp_insert_term( $subject, 'form_entry_subject' );
        }
        if ( ! is_wp_error( $term ) ) {
            $term_id = is_array( $term ) ? $term['term_id'] : $term;
            wp_set_post_terms( $post_id, [ (int) $term_id ], 'form_entry_subject' );
        }

        wp_send_json_success( [ 'message' => 'Thank you! Your message has been received. We will get back to you soon.' ] );
    }

