    public function render_entry_meta_box( $post ) {
        $fields = [
            '_adfs_name'    => 'Full Name',
            '_adfs_email'   => 'Email',
            '_adfs_phone'   => 'Phone',
            '_adfs_subject' => 'Subject',
            '_adfs_message' => 'Message',
        ];
        echo '<table class="form-table pfs-meta-table">';
        foreach ( $fields as $key => $label ) {
            $value = get_post_meta( $post->ID, $key, true );
            echo '<tr>';
            echo '<th><strong>' . esc_html( $label ) . '</strong></th>';
            echo '<td>' . nl2br( esc_html( $value ) ) . '</td>';
            echo '</tr>';
        }
        echo '</table>';
        echo '<p style="color:#64748b;font-size:12px;margin-top:12px;">Submitted: ' . esc_html( get_the_date( 'F j, Y \a\t g:i a', $post ) ) . '</p>';
    }

