    public function admin_column_content( $column, $post_id ) {
        switch ( $column ) {
            case 'adfs_email':
                $email = get_post_meta( $post_id, '_adfs_email', true );
                echo '<a href="mailto:' . esc_attr( $email ) . '">' . esc_html( $email ) . '</a>';
                break;
            case 'adfs_phone':
                echo esc_html( get_post_meta( $post_id, '_adfs_phone', true ) );
                break;
            case 'adfs_message':
                $msg = get_post_meta( $post_id, '_adfs_message', true );
                echo esc_html( wp_trim_words( $msg, 12, '…' ) );
                break;
        }
    }

    public function sortable_columns( $columns ) {
        $columns['adfs_email'] = 'adfs_email';
        return $columns;
